export const GetMarketplacTypes = {
  REQUEST_GET_MARKETPLACE: '@getMarketplace/REQUEST_GET_MARKETPLACE',
  SUCCESS_GET_MARKETPLACE: '@getMarketplace/SUCCESS_GET_MARKETPLACE',
  FAILED_GET_MARKETPLACE: '@getMarketplace/FAILED_GET_MARKETPLACE',
  CLEAR: '@getMarketplace/CLEAR',
};

export interface GetMarketplaceResponse {
  dados: {
    redirectURL: string;
  };
  status: {
    codigoRetorno: number;
    mensagem: string;
  };
}

export type Actions = {
  requestGetMarketplace: (data: Record<string, string>) => Action;
  successGetMarketplace: (data: GetMarketplaceResponse) => Action;
  failedGetMarketplace: () => Action;
  clear: () => Action;
};

export interface GetMarketplaceReducerProps {
  isLoading: boolean;
  isError: boolean;
  data: GetMarketplaceResponse | null;
}

export const initialState: GetMarketplaceReducerProps = {
  isLoading: false,
  isError: false,
  data: null,
};

export const getMarketplaceReducer = createReducer(initialState, {
  [GetMarketplacTypes.REQUEST_GET_MARKETPLACE]: (
    state: GetMarketplaceReducerProps,
  ) => ({
    ...state,
    isLoading: true,
  }),
  [GetMarketplacTypes.SUCCESS_GET_MARKETPLACE]: (
    state: GetMarketplaceReducerProps,
    { data }: { data: GetMarketplaceResponse },
  ) => ({
    ...state,
    isLoading: false,
    isError: false,
    data,
  }),
  [GetMarketplacTypes.FAILED_GET_MARKETPLACE]: (
    state: GetMarketplaceReducerProps,
  ) => ({
    ...state,
    isLoading: false,
    isError: true,
  }),
  [GetMarketplacTypes.CLEAR]: (state: GetMarketplaceReducerProps) => ({
    ...state,
    ...initialState,
  }),
});

export const getMarketplaceActions = {
  requestGetMarketplace: (data: Record<string, string>) => ({
    type: GetMarketplacTypes.REQUEST_GET_MARKETPLACE,
    data,
  }),
  successGetMarketplace: (data: GetMarketplaceResponse) => ({
    type: GetMarketplacTypes.SUCCESS_GET_MARKETPLACE,
    data,
  }),
  failedGetMarketplace: () => ({
    type: GetMarketplacTypes.FAILED_GET_MARKETPLACE,
  }),
  clear: () => ({
    type: GetMarketplacTypes.CLEAR,
  }),
};

export type GetMarketplaceActions = typeof getMarketplaceActions;

export type GetMarketplaceState = ReturnType<typeof getMarketplaceReducer>;

export default getMarketplaceReducer;

