import { useCallback } from 'react';
import { useShallow } from 'zustand/shallow';
import { useRootStore } from '~/store';
import type { RescueCallbacks, RescuePayload } from '../models';
import { RescueStatus } from '../models';
import { clearRescue, performRescue } from '../services';

export function useRescue() {
  const rescue = useRootStore(useShallow(state => state.rescue));

  const rescueRequest = useCallback(async (
    payload: RescuePayload,
    callbacks?: RescueCallbacks,
  ) => {
    await performRescue(payload, callbacks);
  }, []);

  const reset = useCallback(() => {
    clearRescue();
  }, []);

  return {
    ...rescue,
    isLoading: rescue.status === RescueStatus.LOADING,
    isError: rescue.status === RescueStatus.ERROR,
    isSuccess: rescue.status === RescueStatus.SUCCESS,
    rescueRequest,
    reset,
  };
}

import { StateCreator } from 'zustand';

import {
  AirlineMilesSlice,
  createAirlineMilesSlice,
  createMarketplaceSlice,
  createParameterPointsProgramSlice,
  createPermissionSlice,
  createPointsExtractSlice,
  createPointsProductsSlice,
  createRescueSlice,
  MarketplaceSlice,
  ParameterPointsProgramSlice,
  PermissionSlice,
  PointsExtractSlice,
  PointsProductsSlice,
  RescueSlice,
} from '../index';

export type RewardsProgramRootStore = ParameterPointsProgramSlice &
  PermissionSlice &
  AirlineMilesSlice &
  PointsExtractSlice &
  PointsProductsSlice &
  RescueSlice &
  MarketplaceSlice;

type Slice<T> = StateCreator<RewardsProgramRootStore, [], [], T>;
const asSlice = <T>(slice: StateCreator<RewardsProgramRootStore, [], [], T>) =>
  slice as Slice<T>;

export function setRewardsProgramSlices<T extends RewardsProgramRootStore>(
  ...a: Parameters<Slice<T>>
) {
  return {
    ...asSlice<ParameterPointsProgramSlice>(createParameterPointsProgramSlice)(
      ...a,
    ),
    ...asSlice<PermissionSlice>(createPermissionSlice)(...a),
    ...asSlice<AirlineMilesSlice>(createAirlineMilesSlice)(...a),
    ...asSlice<PointsExtractSlice>(createPointsExtractSlice)(...a),
    ...asSlice<PointsProductsSlice>(createPointsProductsSlice)(...a),
    ...asSlice<RescueSlice>(createRescueSlice)(...a),
    ...asSlice<MarketplaceSlice>(createMarketplaceSlice)(...a),
  };
}

import { StateCreator } from 'zustand';

import { AdditionalCardSlice, createAdditionalCardSlice } from '../../services/additionalCard';
import { 
  createParameterPointsProgramSlice, 
  ParameterPointsProgramSlice, 
  createPermissionSlice, 
  PermissionSlice, 
  AirlineMilesSlice,
  createAirlineMilesSlice, 
  createPointsExtractSlice,
  PointsExtractSlice
} from './rewardProgram';

export type CardPlaceRootStore =
  ParameterPointsProgramSlice &
  AdditionalCardSlice &
  PermissionSlice &
  AirlineMilesSlice &
  PointsExtractSlice;

export type Slice<T> = StateCreator<CardPlaceRootStore, [], [], T>;
export const asSlice = <T>(slice: StateCreator<CardPlaceRootStore, [], [], T>) => slice as Slice<T>;

export function setSlicesCardPlace<T extends CardPlaceRootStore>(...a: Parameters<Slice<T>>) {
  return {
    ...asSlice<ParameterPointsProgramSlice>(createParameterPointsProgramSlice)(...a),
    ...asSlice<AdditionalCardSlice>(createAdditionalCardSlice)(...a),
    ...asSlice<PermissionSlice>(createPermissionSlice)(...a),
    ...asSlice<AirlineMilesSlice>(createAirlineMilesSlice)(...a),
    ...asSlice<PointsExtractSlice>(createPointsExtractSlice)(...a),
  };
}

export const EXTRACT_CONSTANTS = {
  DEFAULT_PAGE: 1,
  DEFAULT_PAGE_SIZE: 100,
  SUCCESS_RETURN_CODE: 200,
  BALANCE_SUCCESS_RETURN_CODE: 0,
} as const;

export const ANALYTICS_EVENTS = {
  EXTRACT_SUCCESS: {
    content_type: 'sucesso',
    content_id: 'rewardprogram/v1/extract',
    location_1: 'monetizacao',
    location_2: 'hub_recompensas_spmais',
    location_3: 'extrato_hub_recompensas',
  },
  EXTRACT_ERROR: {
    content_type: 'erro',
    content_id: 'rewardprogram/v1/extract',
    location_1: 'monetizacao',
    location_2: 'hub_recompensas_spmais',
    location_3: 'extrato_hub_recompensas',
  },
  BALANCE_SUCCESS: {
    content_type: 'sucesso',
    content_id: 'rewardprogram/v1/balance',
    location_1: 'monetizacao',
    location_2: 'spmais',
    location_3: 'home',
  },
  BALANCE_ERROR: {
    content_type: 'erro',
    content_id: 'rewardprogram/v1/balance',
    location_1: 'monetizacao',
    location_2: 'spmais',
    location_3: 'home',
  },
} as const;

export const EXTRACT_CONSTANTS = {
  DEFAULT_PAGE: 1,
